function useIsMobile() {
  const [isMobile, setIsMobile] = useState(
    typeof window !== "undefined" ? window.innerWidth <= 760 : false
  );
  useEffect(() => {
    function onResize() {
      setIsMobile(window.innerWidth <= 760);
    }
    window.addEventListener("resize", onResize);
    return () => window.removeEventListener("resize", onResize);
  }, []);
  return isMobile;
}

function useCountdown(target) {
  const [timeLeft, setTimeLeft] = useState(() => target.getTime() - Date.now());
  useEffect(() => {
    const id = setInterval(() => {
      setTimeLeft(target.getTime() - Date.now());
    }, 1000);
    return () => clearInterval(id);
  }, [target]);

  const clamped = Math.max(timeLeft, 0);
  const days = Math.floor(clamped / (1000 * 60 * 60 * 24));
  const hours = Math.floor((clamped / (1000 * 60 * 60)) % 24);
  const minutes = Math.floor((clamped / (1000 * 60)) % 60);
  const seconds = Math.floor((clamped / 1000) % 60);
  return { days, hours, minutes, seconds };
}

export default function SymecsApp() {
  const isMobile = useIsMobile();
  const [page, setPage] = useState("home");
  const [navOpen, setNavOpen] = useState(false);
  const [selectedComps, setSelectedComps] = useState({});
  const [form, setForm] = useState({
    fullName: "",
    instituteName: "",
    contact: "",
    screenshot: null,
    screenshotName: "",
  });
  const [submitted, setSubmitted] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [errorMsg, setErrorMsg] = useState("");

  function toggleComp(comp) {
    setSelectedComps((prev) => {
      const next = { ...prev };
      if (next[comp.id]) {
        delete next[comp.id];
      } else if (comp.type === "squad") {
        const opt = comp.squadOptions[0];
        next[comp.id] = { squadOption: opt.id, players: opt.players, fee: opt.fee };
      } else if (comp.type === "group") {
        next[comp.id] = { members: 1, fee: comp.feePerMember };
      } else {
        next[comp.id] = { fee: comp.fee };
      }
      return next;
    });
  }

  function setSquadOption(comp, squadOptionId) {
    const opt = comp.squadOptions.find((o) => o.id === squadOptionId);
    setSelectedComps((prev) => ({
      ...prev,
      [comp.id]: { squadOption: squadOptionId, players: opt.players, fee: opt.fee },
    }));
  }

  function setGroupMembers(comp, members) {
    setSelectedComps((prev) => ({
      ...prev,
      [comp.id]: { members, fee: comp.feePerMember * members },
    }));
  }

  function handleFileChange(e) {
    const file = e.target.files?.[0];
    if (!file) return;
    setForm((f) => ({ ...f, screenshot: file, screenshotName: file.name }));
  }

  async function handleSubmit(e) {
    e.preventDefault();
    setErrorMsg("");
    const compIds = Object.keys(selectedComps);
    if (compIds.length === 0) return;

    setSubmitting(true);
    try {
      const competitionsPayload = compIds.map((id) => {
        const comp = COMPETITIONS.find((c) => c.id === id);
        const sel = selectedComps[id];
        return {
          id,
          name: comp.name,
          fee: sel.fee,
          players: sel.players || sel.members || 1,
          squadOption: sel.squadOption || null,
        };
      });

      const fd = new FormData();
      fd.append("fullName", form.fullName);
      fd.append("instituteName", form.instituteName);
      fd.append("contact", form.contact);
      fd.append("competitions", JSON.stringify(competitionsPayload));
      fd.append("totalFee", String(totalFee));
      if (form.screenshot) fd.append("screenshot", form.screenshot);

      const res = await fetch("/api/registrations", {
        method: "POST",
        body: fd,
      });

      if (!res.ok) {
        const data = await res.json().catch(() => ({}));
        throw new Error(data.error || "Submission failed");
      }

      setSubmitted(true);
    } catch (err) {
      setErrorMsg(err.message || "Something went wrong. Please try again.");
    } finally {
      setSubmitting(false);
    }
  }

  const totalFee = Object.values(selectedComps).reduce((sum, c) => sum + (c.fee || 0), 0);
  const selectedCount = Object.keys(selectedComps).length;

  return (
    <div style={styles.page}>
      <GlobalStyle />
      <Header page={page} setPage={setPage} isMobile={isMobile} navOpen={navOpen} setNavOpen={setNavOpen} />
      {page === "home" && <Home setPage={setPage} isMobile={isMobile} />}
      {page === "register" && (
        <Register
          form={form}
          setForm={setForm}
          selectedComps={selectedComps}
          toggleComp={toggleComp}
          setSquadOption={setSquadOption}
          setGroupMembers={setGroupMembers}
          handleFileChange={handleFileChange}
          handleSubmit={handleSubmit}
          submitted={submitted}
          submitting={submitting}
          errorMsg={errorMsg}
          totalFee={totalFee}
          selectedCount={selectedCount}
          setPage={setPage}
          isMobile={isMobile}
        />
      )}
      <Footer isMobile={isMobile} />
    </div>
  );
}

